CREATE TEMPORARY TABLE cv_keep AS
  SELECT MIN(id) as keep_id FROM client_visibility GROUP BY configId, clientId;

DELETE FROM client_visibility WHERE id NOT IN (SELECT keep_id FROM cv_keep);

DROP TEMPORARY TABLE cv_keep;

